using System.ComponentModel.DataAnnotations;

namespace Lumeo;

public class DataAnnotationsFormValidator : IFormValidator
{
    public Dictionary<string, List<string>> Validate(object model)
    {
        var results = new List<ValidationResult>();
        var context = new ValidationContext(model);
        Validator.TryValidateObject(model, context, results, true);

        var errors = new Dictionary<string, List<string>>();
        foreach (var result in results)
        {
            foreach (var memberName in result.MemberNames)
            {
                if (!errors.ContainsKey(memberName))
                    errors[memberName] = new List<string>();
                if (result.ErrorMessage is not null)
                    errors[memberName].Add(result.ErrorMessage);
            }
        }
        return errors;
    }

    public List<string> ValidateField(object model, string fieldName)
    {
        var results = new List<ValidationResult>();
        var context = new ValidationContext(model) { MemberName = fieldName };
        var prop = model.GetType().GetProperty(fieldName);
        if (prop is null) return new();
        Validator.TryValidateProperty(prop.GetValue(model), context, results);
        return results.Where(r => r.ErrorMessage is not null).Select(r => r.ErrorMessage!).ToList();
    }
}

@namespace Lumeo
@typeparam TModel

<CascadingValue Value="_context" IsFixed="false">
    <form @onsubmit="HandleSubmit" class="@($"space-y-4 {Class}".Trim())" @attributes="AdditionalAttributes">
        @ChildContent
    </form>
</CascadingValue>

@code {
    [Parameter] public TModel? Model { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public EventCallback<TModel> OnValidSubmit { get; set; }
    [Parameter] public EventCallback<TModel> OnInvalidSubmit { get; set; }
    [Parameter] public IFormValidator? Validator { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private FormContext _context = new();
    // JSON snapshot of the Model captured at initialization. Used by ResetValues() to
    // restore the Model to its initial state. Captured via System.Text.Json round-trip
    // so it covers nested objects and record types without needing to know the schema.
    private string? _initialModelSnapshot;

    protected override Task OnInitializedAsync()
    {
        CaptureInitialSnapshot();
        return Task.CompletedTask;
    }

    private void CaptureInitialSnapshot()
    {
        if (Model is null)
        {
            _initialModelSnapshot = null;
            return;
        }

        try
        {
            _initialModelSnapshot = System.Text.Json.JsonSerializer.Serialize(Model);
        }
        catch
        {
            // If the model is not JSON-serializable we silently skip the snapshot.
            // ResetValues() will then be a no-op (besides clearing errors).
            _initialModelSnapshot = null;
        }
    }

    private async Task HandleSubmit()
    {
        if (Model is null) return;

        _context.IsSubmitting = true;
        StateHasChanged();

        try
        {
            if (Validator is not null)
            {
                // Merge sync validation results with any async errors already in the context
                // so per-field async validators (e.g. "username taken") survive a sync re-validate.
                var syncErrors = Validator.Validate(Model);
                foreach (var kvp in syncErrors)
                {
                    _context.Errors[kvp.Key] = kvp.Value;
                }
            }

            if (_context.IsValid)
            {
                await OnValidSubmit.InvokeAsync(Model);
            }
            else
            {
                await OnInvalidSubmit.InvokeAsync(Model);
            }
        }
        finally
        {
            _context.IsSubmitting = false;
            StateHasChanged();
        }
    }

    public void ValidateField(string fieldName)
    {
        if (Model is null || Validator is null) return;
        var errors = Validator.ValidateField(Model, fieldName);
        if (errors.Count > 0)
            _context.Errors[fieldName] = errors;
        else
            _context.Errors.Remove(fieldName);
        StateHasChanged();
    }

    public void Reset()
    {
        _context.Reset();
        StateHasChanged();
    }

    /// <summary>
    /// Restores the <see cref="Model"/>'s public read/write properties to the values
    /// captured during <see cref="OnInitializedAsync"/>, and clears validation errors.
    /// <para>
    /// Implementation note: the snapshot is taken via a <c>System.Text.Json</c> round-trip,
    /// so the model type MUST be JSON-round-trippable — i.e. public properties with both a
    /// getter and a setter (or an init-only setter for record types), no recursive cycles,
    /// and serializable property types. Properties that are read-only, write-only, or marked
    /// <c>[JsonIgnore]</c> will NOT be restored. If the model failed to serialize at
    /// initialization time this method falls back to <see cref="Reset"/> behavior
    /// (errors cleared, values untouched).
    /// </para>
    /// </summary>
    public void ResetValues()
    {
        if (Model is not null && _initialModelSnapshot is not null)
        {
            try
            {
                var restored = System.Text.Json.JsonSerializer.Deserialize<TModel>(_initialModelSnapshot);
                if (restored is not null)
                {
                    CopyPublicProperties(restored, Model);
                }
            }
            catch
            {
                // Round-trip failed; leave Model untouched but still clear errors below.
            }
        }

        _context.Reset();
        StateHasChanged();
    }

    // Copies public read/write properties from source to destination using reflection.
    // We mutate the existing Model instance (rather than reassigning the Model parameter)
    // because the parent component owns Model and reassigning a [Parameter] from inside
    // the child would be overwritten on the next render pass.
    private static void CopyPublicProperties(TModel source, TModel destination)
    {
        var type = typeof(TModel);
        foreach (var prop in type.GetProperties(System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance))
        {
            if (!prop.CanRead || !prop.CanWrite) continue;
            if (prop.GetIndexParameters().Length > 0) continue;
            try
            {
                var value = prop.GetValue(source);
                prop.SetValue(destination, value);
            }
            catch
            {
                // Skip properties whose setter throws (init-only on a non-record class, etc.).
            }
        }
    }
}

namespace Lumeo;

public class FormContext
{
    public Dictionary<string, List<string>> Errors { get; set; } = new();
    public HashSet<string> DirtyFields { get; set; } = new();
    public bool IsSubmitting { get; set; }
    public bool IsValid => Errors.Count == 0 || Errors.All(e => e.Value.Count == 0);

    // Tracks which fields currently have an in-flight async validation. The field
    // name (or a synthetic key when Name is unset) is added when validation starts
    // and removed when it completes or is cancelled.
    public HashSet<string> ValidatingFields { get; set; } = new();

    /// <summary>
    /// True when at least one FormField has an async validation in flight. Useful
    /// for disabling submit buttons while server-side checks are pending.
    /// </summary>
    public bool IsAnyFieldValidating => ValidatingFields.Count > 0;

    public List<string> GetFieldErrors(string fieldName) =>
        Errors.TryGetValue(fieldName, out var errors) ? errors : new();

    public bool HasError(string fieldName) => GetFieldErrors(fieldName).Count > 0;
    public bool IsDirty(string fieldName) => DirtyFields.Contains(fieldName);
    public bool IsFieldValidating(string fieldName) => ValidatingFields.Contains(fieldName);

    public void MarkDirty(string fieldName) => DirtyFields.Add(fieldName);

    public void MarkValidating(string fieldName, bool validating)
    {
        if (validating) ValidatingFields.Add(fieldName);
        else ValidatingFields.Remove(fieldName);
    }

    public void SetFieldError(string fieldName, string? error)
    {
        if (string.IsNullOrEmpty(error))
            Errors.Remove(fieldName);
        else
            Errors[fieldName] = new List<string> { error };
    }

    public void ClearErrors() => Errors.Clear();
    public void ClearFieldErrors(string fieldName) => Errors.Remove(fieldName);

    public void Reset()
    {
        Errors.Clear();
        DirtyFields.Clear();
        ValidatingFields.Clear();
        IsSubmitting = false;
    }
}

@namespace Lumeo

<p class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</p>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"text-[0.8rem] text-muted-foreground {Class}".Trim();
}

@namespace Lumeo
@using Lumeo.Internal
@implements IDisposable

@{
    var context = new FormFieldContext(Name, EffectiveError, IsValidating);
}

<CascadingValue Value="context" IsFixed="false">
    <div class="@CssClass" @attributes="AdditionalAttributes">
        @if (Orientation == Lumeo.Orientation.Vertical)
        {
            @if (Label is not null)
            {
                <Label>
                    <span class="inline-flex items-center gap-1.5">
                        @Label
                        @if (Required)
                        {
                            <span class="text-destructive ml-0.5">*</span>
                        }
                        @if (IsValidating)
                        {
                            <Spinner Size="Lumeo.Size.Sm" Color="text-muted-foreground" />
                        }
                    </span>
                </Label>
            }
            @ChildContent
            @if (HelpText is not null && EffectiveError is null)
            {
                <p class="text-xs text-muted-foreground">@HelpText</p>
            }
            @if (EffectiveError is not null)
            {
                <p class="text-xs text-destructive" role="alert" aria-live="polite">@EffectiveError</p>
            }
        }
        else
        {
            <div class="grid grid-cols-[auto_1fr] items-center gap-x-4 gap-y-1">
                @if (Label is not null)
                {
                    <Label Class="@(Cx.Join("text-right", LabelWidth is not null ? $"w-[{LabelWidth}]" : null))">
                        <span class="inline-flex items-center justify-end gap-1.5">
                            @Label
                            @if (Required)
                            {
                                <span class="text-destructive ml-0.5">*</span>
                            }
                            @if (IsValidating)
                            {
                                <Spinner Size="Lumeo.Size.Sm" Color="text-muted-foreground" />
                            }
                        </span>
                    </Label>
                }
                <div>
                    @ChildContent
                    @if (HelpText is not null && EffectiveError is null)
                    {
                        <p class="text-xs text-muted-foreground mt-1">@HelpText</p>
                    }
                    @if (EffectiveError is not null)
                    {
                        <p class="text-xs text-destructive mt-1" role="alert" aria-live="polite">@EffectiveError</p>
                    }
                </div>
            </div>
        }
    </div>
</CascadingValue>

@code {
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? HelpText { get; set; }
    [Parameter] public string? Error { get; set; }
    [Parameter] public bool Required { get; set; }
    [Parameter] public Lumeo.Orientation Orientation { get; set; } = Lumeo.Orientation.Vertical;
    [Parameter] public string? LabelWidth { get; set; }
    [Parameter] public string? Name { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // --- Async validation ---
    /// <summary>
    /// Optional async validator. Receives the current <see cref="Value"/>, returns
    /// null when valid or an error message string otherwise. The result is stored
    /// in <see cref="FormContext.Errors"/> against <see cref="Name"/>.
    /// </summary>
    [Parameter] public Func<object?, Task<string?>>? AsyncValidator { get; set; }

    /// <summary>Debounce window in ms. 0 disables debouncing.</summary>
    [Parameter] public int AsyncValidationDebounceMs { get; set; } = 0;

    /// <summary>When async validation runs. Defaults to <see cref="AsyncValidationTrigger.OnBlur"/>.</summary>
    [Parameter] public AsyncValidationTrigger AsyncValidateOn { get; set; } = AsyncValidationTrigger.OnBlur;

    /// <summary>
    /// Current value of the bound input. Required for <see cref="AsyncValidationTrigger.OnChange"/>
    /// auto-triggering; also passed to the validator on blur. If unset, consumers may invoke
    /// <see cref="ValidateAsync(object?)"/> directly.
    /// </summary>
    [Parameter] public object? Value { get; set; }

    /// <summary>Fired whenever <see cref="IsValidating"/> flips.</summary>
    [Parameter] public EventCallback<bool> OnValidatingChanged { get; set; }

    public bool IsValidating { get; private set; }

    // Bug D fix: receive the parent Form's context so Reset() clears cascade to child fields.
    [CascadingParameter] private FormContext? ParentFormContext { get; set; }

    // Use live errors from FormContext when available; fall back to the manually-set Error param.
    private string? EffectiveError =>
        ParentFormContext is { } pc && !string.IsNullOrEmpty(Name)
            ? pc.GetFieldErrors(Name).FirstOrDefault() ?? Error
            : Error;

    private string CssClass => Orientation == Lumeo.Orientation.Vertical
        ? $"space-y-2 {Class}".Trim()
        : $"{Class}".Trim();

    // Async machinery
    private DebouncedValue<object?>? _debouncer;
    private int _lastDebounceMs = -1;
    private CancellationTokenSource? _cts;
    private object? _previousValue;
    private bool _hasPreviousValue;
    // Synthetic key used when no Name is set so the validating-fields set still aggregates.
    private string FieldKey => string.IsNullOrEmpty(Name) ? $"__field_{GetHashCode()}" : Name!;

    protected override async Task OnParametersSetAsync()
    {
        // Re-create the debouncer if the window changed.
        if (_lastDebounceMs != AsyncValidationDebounceMs)
        {
            _debouncer?.Dispose();
            _debouncer = AsyncValidationDebounceMs > 0
                ? new DebouncedValue<object?>(AsyncValidationDebounceMs)
                : null;
            _debouncer?.OnChanged(RunValidationAsync);
            _lastDebounceMs = AsyncValidationDebounceMs;
        }

        // Detect value changes for OnChange trigger. Skip the first parameter-set
        // pass so we don't auto-validate before the user has interacted.
        if (AsyncValidator is not null && AsyncValidateOn == AsyncValidationTrigger.OnChange)
        {
            if (_hasPreviousValue && !Equals(_previousValue, Value))
            {
                ScheduleValidation(Value);
            }
        }
        _previousValue = Value;
        _hasPreviousValue = true;

        await Task.CompletedTask;
    }

    /// <summary>
    /// Manually trigger async validation (e.g. wire to an input's @onblur). Honors
    /// the configured debounce window. Passes <paramref name="value"/> to the validator;
    /// if null the current <see cref="Value"/> parameter is used.
    /// </summary>
    public Task ValidateAsync(object? value = null)
    {
        if (AsyncValidator is null) return Task.CompletedTask;
        ScheduleValidation(value ?? Value);
        return Task.CompletedTask;
    }

    private void ScheduleValidation(object? value)
    {
        if (AsyncValidator is null) return;
        if (_debouncer is not null)
        {
            _debouncer.Set(value);
        }
        else
        {
            _ = RunValidationAsync(value);
        }
    }

    private async Task RunValidationAsync(object? value)
    {
        var validator = AsyncValidator;
        if (validator is null) return;

        // Cancel previous in-flight call.
        _cts?.Cancel();
        _cts?.Dispose();
        var cts = new CancellationTokenSource();
        _cts = cts;
        var token = cts.Token;

        await SetValidatingAsync(true);

        string? error = null;
        try
        {
            error = await validator(value).ConfigureAwait(true);
        }
        catch (OperationCanceledException)
        {
            return;
        }
        catch
        {
            // Swallow to avoid breaking the form; surface no error rather than throwing.
        }

        if (token.IsCancellationRequested) return;

        if (ParentFormContext is { } ctx && !string.IsNullOrEmpty(Name))
        {
            ctx.SetFieldError(Name!, error);
        }
        else
        {
            // No parent context / no Name: fall back to the local Error parameter via re-render.
            Error = error;
        }

        await SetValidatingAsync(false);
        StateHasChanged();
    }

    private async Task SetValidatingAsync(bool validating)
    {
        if (IsValidating == validating) return;
        IsValidating = validating;
        if (ParentFormContext is not null)
        {
            ParentFormContext.MarkValidating(FieldKey, validating);
        }
        if (OnValidatingChanged.HasDelegate)
        {
            await OnValidatingChanged.InvokeAsync(validating);
        }
        StateHasChanged();
    }

    public void Dispose()
    {
        _debouncer?.Dispose();
        _cts?.Cancel();
        _cts?.Dispose();
        if (ParentFormContext is not null)
        {
            ParentFormContext.MarkValidating(FieldKey, false);
        }
    }

    public enum AsyncValidationTrigger
    {
        OnBlur,
        OnChange
    }

    public record FormFieldContext(string? Name, string? Error, bool IsValidating)
    {
        public bool HasError => !string.IsNullOrEmpty(Error);
    }
}

